function a(e){return e||""}function o(e){if(!e)return"";const r=Date.now()-new Date(e).getTime(),t=Math.floor(r/6e4);if(t<1)return"just now";if(t<60)return`${t}m ago`;const n=Math.floor(t/60);return n<24?`${n}h ago`:`${Math.floor(n/24)}d ago`}function c(e){switch(e){case"healthy":case"success":case"succeeded":case"Running":return"text-success";case"degraded":case"warning":case"Pending":return"text-warning";case"failing":case"failed":case"CrashLoopBackOff":case"ImagePullBackOff":return"text-error";default:return"text-muted-foreground"}}function u(e){switch(e){case"healthy":case"success":case"succeeded":return"bg-success/10 text-success border-success/20";case"degraded":case"warning":return"bg-warning/10 text-warning border-warning/20";case"failing":case"failed":return"bg-error/10 text-error border-error/20";default:return"bg-muted text-muted-foreground border-border"}}function i(e){const r=e.toLowerCase();return r.includes("prod")?"text-error":r.includes("stag")?"text-warning":r.includes("dev")?"text-info":"text-muted-foreground"}export{u as a,i as e,o as r,c as s,a as t};
